from datetime import datetime

def get_theme(condition: str = "") -> dict:
    hour = datetime.now().hour
    c = condition.lower()
    is_night = (hour < 6 or hour >= 20)

    if is_night:
        return dict(a1="#7c4dff", a2="#2979ff", glow="rgba(124,77,255,0.15)", hero="linear-gradient(135deg,#7c4dff,#2979ff)", body_bg="radial-gradient(ellipse at 20% 50%,rgba(20,0,80,0.18) 0%,transparent 60%)", label="Night Mode 🌙", cls="theme-night")
    if any(k in c for k in ["thunder", "storm"]):
        return dict(a1="#ff4081", a2="#7c4dff", glow="rgba(255,64,129,0.15)", hero="linear-gradient(135deg,#ff4081,#7c4dff)", body_bg="radial-gradient(ellipse at 50% 0%,rgba(80,0,150,0.22) 0%,transparent 60%)", label="Storm Alert ⛈️", cls="theme-storm")
    if any(k in c for k in ["rain", "drizzle", "shower"]):
        return dict(a1="#00e5ff", a2="#2979ff", glow="rgba(0,229,255,0.13)", hero="linear-gradient(135deg,#00e5ff,#2979ff)", body_bg="radial-gradient(ellipse at 30% 30%,rgba(0,100,200,0.13) 0%,transparent 60%)", label="Rainy Day 🌧️", cls="theme-rain")
    if any(k in c for k in ["cloud", "overcast", "fog", "mist"]):
        return dict(a1="#90caf9", a2="#7ecdc8", glow="rgba(144,202,249,0.10)", hero="linear-gradient(135deg,#90caf9,#7ecdc8)", body_bg="radial-gradient(ellipse at 50% 30%,rgba(100,120,150,0.11) 0%,transparent 60%)", label="Cloudy ☁️", cls="theme-cloud")
    if any(k in c for k in ["clear", "sunny", "fair", "mainly"]):
        return dict(a1="#ffd166", a2="#ff9f43", glow="rgba(255,209,102,0.13)", hero="linear-gradient(135deg,#ffd166,#ff9f43)", body_bg="radial-gradient(ellipse at 60% 20%,rgba(255,200,50,0.10) 0%,transparent 55%)", label="Sunny ☀️", cls="theme-sunny")
    return dict(a1="#00e5ff", a2="#2979ff", glow="rgba(0,229,255,0.12)", hero="linear-gradient(135deg,#00e5ff,#2979ff)", body_bg="radial-gradient(ellipse at 20% 50%,rgba(41,121,255,0.07) 0%,transparent 60%)", label="", cls="theme-default")

def _rgb(hex_color: str) -> str:
    h = hex_color.lstrip('#')
    return ','.join(str(int(h[i:i+2], 16)) for i in (0, 2, 4))

def inject_css(T: dict):
    a1, a2, glow, hero, bbg, cls = T["a1"], T["a2"], T["glow"], T["hero"], T["body_bg"], T["cls"]
    r1, r2 = _rgb(a1), _rgb(a2)
    return f'<style>:root{{--a1:{a1};--a2:{a2};--glow:{glow};--hero:{hero};--text-primary:#e8f4f8;--text-muted:#7ecdc8;}}.stApp{{background:#020810!important;background-image:{bbg}!important;font-family:Rajdhani,sans-serif!important;color:var(--text-primary)!important}}#MainMenu,footer,header{{visibility:hidden}}.block-container{{padding:1rem 2rem 2rem!important;max-width:100%!important}}.nexus-header{{display:flex;align-items:center;justify-content:space-between;padding:1rem 2rem;background:rgba(0,0,0,.3);border:1px solid rgba({r1},.2);border-radius:16px;margin-bottom:1.5rem;backdrop-filter:blur(20px)}}.nexus-logo{{font-family:Orbitron,sans-serif;font-size:1.8rem;font-weight:800;background:{hero};-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:3px}}.glass-card{{background:rgba(10,15,30,.72);border:1px solid rgba({r1},.2);border-radius:16px;padding:1.4rem;backdrop-filter:blur(20px);margin-bottom:1rem;transition:all .3s ease}}.glass-card:hover{{border-color:rgba({r1},.38);transform:translateY(-2px)}}.metric-card{{background:linear-gradient(135deg,rgba({r1},.07),rgba({r2},.05));border:1px solid rgba({r1},.2);border-radius:12px;padding:1rem;text-align:center;transition:all .3s ease}}.metric-icon{{font-size:1.6rem;margin-bottom:.3rem}}.metric-label{{font-family:Rajdhani,sans-serif;font-size:.7rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-muted)}}.metric-value{{font-family:Orbitron,sans-serif;font-size:1.4rem;font-weight:600;color:var(--a1)}}.temp-hero{{font-family:Orbitron,sans-serif;font-size:5rem;font-weight:800;background:{hero};-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin:.5rem 0}}.section-title{{font-family:Orbitron,sans-serif;font-size:.8rem;letter-spacing:3px;text-transform:uppercase;color:var(--a1);margin-bottom:.8rem;padding-bottom:.5rem;border-bottom:1px solid rgba({r1},.2)}}.gauge-container{{margin:.4rem 0}}.gauge-label{{display:flex;justify-content:space-between;font-size:.75rem;color:var(--text-muted)}}.gauge-track{{background:rgba(255,255,255,.06);border-radius:99px;height:6px;overflow:hidden}}.gauge-fill{{height:100%;border-radius:99px;transition:width 1s ease}}.alert-critical{{background:linear-gradient(135deg,rgba(255,50,50,.12),rgba(255,100,50,.08));border:1px solid rgba(255,80,80,.4);border-radius:12px;padding:.8rem 1rem;margin:.4rem 0}}.alert-warning{{background:linear-gradient(135deg,rgba(255,193,7,.1),rgba(255,152,0,.06));border:1px solid rgba(255,193,7,.3);border-radius:12px;padding:.8rem 1rem;margin:.4rem 0}}.alert-info{{background:linear-gradient(135deg,rgba(0,229,255,.08),rgba(41,121,255,.05));border:1px solid rgba(0,229,255,.2);border-radius:12px;padding:.8rem 1rem;margin:.4rem 0}}.rec-chip{{display:inline-block;background:rgba({r1},.07);border:1px solid rgba({r1},.18);border-radius:20px;padding:.2rem .7rem;font-size:.78rem;margin:.15rem;color:var(--text-primary)}}.rec-chip-warn{{background:rgba(255,100,50,.07);border-color:rgba(255,100,50,.22)}}.offline-banner{{background:linear-gradient(135deg,rgba(255,152,0,.15),rgba(255,87,34,.08));border:1px solid rgba(255,152,0,.4);border-radius:12px;padding:.8rem 1rem;margin:.4rem 0;color:#ff9f43}}.stButton>button{{background:linear-gradient(135deg,var(--a2),var(--a1))!important;color:#000!important;border:none!important;border-radius:10px!important;font-weight:600!important;transition:all .3s ease!important}}.stButton>button:hover{{transform:translateY(-2px)!important}}</style>'